import{_ as a,o as t,c as i,a2 as r}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Widget Areas","description":"Akurai Widget Areas","frontmatter":{"title":"Widget Areas","description":"Akurai Widget Areas","weight":90,"extra":{"order":90},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/widget-areas"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/widget-areas"}],["meta",{"property":"og:title","content":"Widget Areas"}],["meta",{"property":"og:description","content":"Akurai Widget Areas"}],["meta",{"name":"twitter:title","content":"Widget Areas"}],["meta",{"name":"twitter:description","content":"Akurai Widget Areas"}]]},"headers":[],"relativePath":"docs/akurai/widget-areas.md","filePath":"docs/akurai/widget-areas.md"}'),o={name:"docs/akurai/widget-areas.md"};function s(d,e,n,l,g,h){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="widget-areas" tabindex="-1">Widget Areas <a class="header-anchor" href="#widget-areas" aria-label="Permalink to &quot;Widget Areas&quot;">​</a></h1><p>Akurai has multiple widget areas to give you more options for laying out your content.</p><hr><h2 id="widget-area-layouts" tabindex="-1">Widget Area Layouts <a class="header-anchor" href="#widget-area-layouts" aria-label="Permalink to &quot;Widget Area Layouts&quot;">​</a></h2><p>There are 7 widget areas available:</p><ol><li>Main Sidebar</li><li>Left Sidebar</li><li>Review Page Sidebar</li><li>Footer Widgets #1</li><li>Footer Widgets #2</li><li>Footer Widgets #3</li><li>Footer Widgets #4</li></ol><h3 id="main-sidebar" tabindex="-1">Main Sidebar <a class="header-anchor" href="#main-sidebar" aria-label="Permalink to &quot;Main Sidebar&quot;">​</a></h3><p><strong>Main Sidebar</strong> is displayed on pages with the <strong>Right Sidebar</strong> page template.</p><h3 id="left-sidebar" tabindex="-1">Left Sidebar <a class="header-anchor" href="#left-sidebar" aria-label="Permalink to &quot;Left Sidebar&quot;">​</a></h3><p><strong>Left Sidebar</strong> is displayed on pages with the <strong>Left Sidebar</strong> page template.</p><h3 id="review-page-sidebar" tabindex="-1">Review Page Sidebar <a class="header-anchor" href="#review-page-sidebar" aria-label="Permalink to &quot;Review Page Sidebar&quot;">​</a></h3><p><strong>Review Page Sidebar</strong> is displayed on review pages with <strong>Review with Sidebar</strong> template where you can add review page blocks (also via shortcodes).</p><h3 id="footer-widgets" tabindex="-1">Footer Widgets <a class="header-anchor" href="#footer-widgets" aria-label="Permalink to &quot;Footer Widgets&quot;">​</a></h3><p>The theme footer is divided into 4 equal parts, each one of them displaying a single widget area. This way you can have a long footer without having to worry about their responsive structure.</p>',14)])])}const u=a(o,[["render",s]]);export{p as __pageData,u as default};
